\[
\kappa^{n}=\frac{I I(\mathbf{w}, \mathbf{w})}{I(\mathbf{w}, \mathbf{w})}
\]

\[
\mathbf{Q}=R(t) \tilde{\mathbf{Q}}
\]

\[
\begin{gathered}
\mathbf{U}=\mathbf{v}_{t} \\
\mathbf{\Omega} \wedge \tilde{\mathbf{Q}}=R_{t} \tilde{\mathbf{Q}}
\end{gathered}
\]

\[
\mathbf{Q}_{t}=\tilde{\mathbf{Q}}_{t}+\mathbf{\Omega} \wedge \tilde{\mathbf{Q}}
\]

\[
\mathbf{r}_{s}=\lambda_{s} \mathbf{Q}+\lambda \mathbf{Q}_{s}
\]

\[
\begin{aligned}
& \mathbf{r}_{s} \cdot \mathbf{n}=0 \\
& \mathbf{Q} \cdot \mathbf{n}=0
\end{aligned}
\]

\[
\mathbf{n}=\frac{\mathbf{Q} \wedge \mathbf{Q}_{s}}{\left|\mathbf{Q} \wedge \mathbf{Q}_{s}\right|}
\]

\[
\begin{aligned}
I I\left(\mathbf{Q}, \mathbf{r}_{s}\right) & =-\mathbf{Q} \cdot \mathbf{L}\left(\mathbf{r}_{s}\right) \\
& =-\mathbf{Q} \cdot \mathbf{n}_{s}
\end{aligned}
\]

\[
\mathbf{n}\left(s, t_{0}\right)=\frac{\mathbf{Q} \wedge \mathbf{Q}_{s}}{\left|\mathbf{Q} \wedge \mathbf{Q}_{s}\right|}
\]

\[
\kappa^{p}=\frac{\mathbf{Q}_{s s} \cdot \mathbf{n}}{\left|\mathbf{Q}_{s}\right|^{2}}
\]

\[
\kappa^{p}=\frac{\lambda \kappa^{s}}{\sin ^{2} \theta}
\]

\[
K=\frac{\kappa^{p} \kappa^{t}}{\lambda}
\]

\[
\mathbf{Q}_{t}=\frac{(\mathbf{U} \wedge \mathbf{Q}) \wedge \mathbf{Q}}{\lambda}
\]

\[
\tilde{\mathbf{Q}}_{t}=\frac{(\mathbf{U} \wedge \tilde{\mathbf{Q}}) \wedge \tilde{\mathbf{Q}}}{\lambda}-\mathbf{\Omega} \wedge \tilde{\mathbf{Q}}
\]

\[
\mathbf{r}_{t}=\left[\frac{\mathbf{Q}_{t} \cdot \mathbf{n}}{\kappa^{t}}\right] \mathbf{Q}
\]

\[
\kappa^{t}=\frac{\mathbf{r}_{t t} \cdot \mathbf{n}}{\mathbf{r}_{t} \cdot \mathbf{r}_{t}}
\]

\[
\mathbf{r}_{t}=\left(\lambda_{t}+\mathbf{Q} \cdot \mathbf{U}\right) \mathbf{Q}
\]

\[
\kappa^{t}=\frac{\mathbf{Q}_{t} \cdot \mathbf{n}}{\left(\lambda_{t}+\mathbf{Q} \cdot \mathbf{U}\right)}
\]

\[
\lambda=-\frac{\mathbf{U} \cdot \mathbf{n}}{\mathbf{Q}_{t} \cdot \mathbf{n}}
\]

\[
\lambda=-\frac{\mathbf{U} \cdot \mathbf{n}}{\tilde{\mathbf{Q}}_{t} \cdot \mathbf{n}+(\boldsymbol{\Omega} \wedge \tilde{\mathbf{Q}}) \cdot \mathbf{n}}
\]

\[
\begin{aligned}
& \mathbf{G}=\left[\begin{array}{cc}
1 & \cos \theta \\
\cos \theta & 1
\end{array}\right] \\
& \mathbf{D}=\left[\begin{array}{cc}
\kappa^{s} & 0 \\
0 & \kappa^{t}
\end{array}\right]
\end{aligned}
\]

\[
\tan \theta=\frac{\lambda\left|\mathbf{Q}_{s}\right|}{\lambda_{s}}
\]

\[
\kappa^{s}=\frac{\kappa^{p} \sin ^{2} \theta}{\lambda}
\]

\[
\kappa^{t}=-\frac{\mathbf{U} \cdot \mathbf{n}}{\lambda\left(\lambda_{t}+\tilde{\mathbf{Q}} \cdot \mathbf{U}\right)}
\]

\[
K=\frac{\kappa^{p} \kappa^{t}}{\lambda}
\]

\[
\begin{aligned}
H & =\frac{1}{2}\left[\frac{\kappa^{p}}{\lambda}+\kappa^{t} \operatorname{cosec}^{2} \theta\right] \\
\kappa_{1,2} & =H \pm \sqrt{H^{2}-K}
\end{aligned}
\]

\[
\tilde{\mathbf{Q}}_{t}^{(i)}=\left[\left(\mathbf{U} \wedge \tilde{\mathbf{Q}}^{(i)}\right) \wedge \tilde{\mathbf{Q}}^{(i)}\right] \quad \frac{1}{\lambda^{(i)}}, \quad-\mathbf{\Omega} \wedge \tilde{\mathbf{Q}}^{(i)}
\]

\[
\delta(t)=\tilde{\mathbf{Q}}^{(2)}-\tilde{\mathbf{Q}}^{(1)}
\]

\[
\tilde{\mathbf{Q}}^{(1)}(0)=\tilde{\mathbf{Q}}^{(2)}(0)=\tilde{\mathbf{Q}}
\]

\[
\Delta R=\frac{1}{\kappa^{t 2}}-\frac{1}{\kappa^{t 1}}
\]

\[
\Delta R=\Delta \hat{R}+R^{\mathrm{error}}
\]

\[
\Delta \hat{R}=-\frac{\lambda^{3}}{(\mathbf{U} \cdot \mathbf{n})^{2}} \delta_{t t} \cdot \mathbf{n}
\]

\[
\left|R^{\text {error }}\right| \approx 9 \lambda|\delta|+\lambda^{3}|\delta| \frac{\left|\Omega_{t}\right|}{(\mathbf{U} \cdot \mathbf{n})^{2}}+\lambda|\Delta \lambda| \frac{\mathbf{U}_{t} \cdot \mathbf{n}}{(\mathbf{U} \cdot \mathbf{n})^{2}}
\]

\[
|\delta| \ll \frac{\Delta R}{9 \lambda}
\]

