\]

\[
\left.\frac{\partial \tilde{\mathbf{Q}}}{\partial t}\right|_{\bar{s}}=\beta \mathbf{n}
\]

\[
\begin{aligned}
\tilde{\mathbf{Q}} & =\tilde{\mathbf{Q}}^{*} \\
\tilde{\mathbf{Q}}_{t} & =\tilde{\mathbf{Q}}_{t}^{*}
\end{aligned}
\]

\[
\left.\frac{\partial \bar{s}}{\partial t}\right|_{s}=\frac{\left.\tilde{\mathbf{Q}}_{t} \cdot \frac{\partial \tilde{\mathbf{Q}}}{\partial \bar{s}}\right|_{t}}{\left.\left|\frac{\partial \tilde{\mathbf{Q}}}{\partial \bar{s}}\right|_{t}\right|^{2}}
\]

\[
