\mathbf{Q}^{(2)} & =\mathbf{Q} \\
\mathbf{Q}^{(1)} & =\mathbf{Q}+\Delta \mathbf{Q} \\
\lambda^{(2)} & =\lambda \\
\lambda^{(1)} & =\lambda+\Delta \lambda \\
\mathbf{Q}^{(2)} \cdot \mathbf{n} & =0 \\
\mathbf{Q}^{(1)} \cdot \mathbf{n} & =\Delta \mathbf{Q} \cdot \mathbf{n}
\end{aligned}
\]

\[
\Delta \hat{R}=\frac{(\mathrm{U} \cdot \mathbf{n})^{2}}{\lambda^{3}} \frac{1}{\delta_{t t} \cdot \mathbf{n}}
\]

\[
\Delta R=\Delta \hat{R}+R^{\text {error }}
\]

\[
R^{\text {error }}=R^{\Delta \lambda}+R^{\Delta Q}+R^{\mathbf{n}}
\]

\[
\begin{aligned}
R^{\Delta \lambda}= & \Delta \lambda\left[\frac{3}{\lambda \kappa^{\imath 2}}+\frac{4 \mathbf{U} \cdot \mathbf{Q}}{\mathbf{U} \cdot \mathbf{n}}+\frac{\lambda \mathbf{U}_{t} \cdot \mathbf{n}}{(\mathbf{U} \cdot \mathbf{n})^{2}}\right. \\
& \left.+\frac{2 \lambda(\mathbf{U} \cdot \mathbf{Q})(\mathbf{\Omega} \wedge \mathbf{Q}) \cdot \mathbf{n}}{(\mathbf{U} \cdot \mathbf{n})^{2}}+\frac{\lambda(\mathbf{U} \wedge \mathbf{\Omega}) \cdot \mathbf{n}}{(\mathbf{U} \cdot \mathbf{n})^{2}}\right]
\end{aligned}
\]
